     1→package api
     2→
     3→import (
     4→	"context"
     5→	"encoding/json"
     6→	"net/http"
     7→	"strconv"
     8→)
     9→
    10→type contextKey string
    11→
    12→const requestIDKey contextKey = "request_id"
    13→
    14→func withRequestID(ctx context.Context, id string) context.Context {
    15→	return context.WithValue(ctx, requestIDKey, id)
    16→}
    17→
    18→func getRequestID(ctx context.Context) string {
    19→	if id, ok := ctx.Value(requestIDKey).(string); ok {
    20→		return id
    21→	}
    22→	return ""
    23→}
    24→
    25→type meta struct {
    26→	RequestID string `json:"request_id"`
    27→}
    28→
    29→type listMeta struct {
    30→	RequestID string `json:"request_id"`
    31→	Page      int    `json:"page"`
    32→	PerPage   int    `json:"per_page"`
    33→	Total     int    `json:"total"`
    34→}
    35→
    36→type envelope struct {
    37→	Data any  `json:"data"`
    38→	Meta meta `json:"meta"`
    39→}
    40→
    41→type listEnvelope struct {
    42→	Data any      `json:"data"`
    43→	Meta listMeta `json:"meta"`
    44→}
    45→
    46→type apiError struct {
    47→	Code    string `json:"code"`
    48→	Message string `json:"message"`
    49→}
    50→
    51→type errorEnvelope struct {
    52→	Error apiError `json:"error"`
    53→	Meta  meta     `json:"meta"`
    54→}
    55→
    56→func RespondJSON(w http.ResponseWriter, r *http.Request, status int, data any) {
    57→	w.Header().Set("Content-Type", "application/json")
    58→	w.WriteHeader(status)
    59→	json.NewEncoder(w).Encode(envelope{
    60→		Data: data,
    61→		Meta: meta{RequestID: getRequestID(r.Context())},
    62→	})
    63→}
    64→
    65→func RespondList(w http.ResponseWriter, r *http.Request, status int, data any, page, perPage, total int) {
    66→	w.Header().Set("Content-Type", "application/json")
    67→	w.WriteHeader(status)
    68→	json.NewEncoder(w).Encode(listEnvelope{
    69→		Data: data,
    70→		Meta: listMeta{RequestID: getRequestID(r.Context()), Page: page, PerPage: perPage, Total: total},
    71→	})
    72→}
    73→
    74→func RespondError(w http.ResponseWriter, r *http.Request, status int, code, message string) {
    75→	w.Header().Set("Content-Type", "application/json")
    76→	w.WriteHeader(status)
    77→	json.NewEncoder(w).Encode(errorEnvelope{
    78→		Error: apiError{Code: code, Message: message},
    79→		Meta:  meta{RequestID: getRequestID(r.Context())},
    80→	})
    81→}
    82→
    83→func ParsePagination(r *http.Request) (page, perPage int) {
    84→	page = 1
    85→	perPage = 25
    86→	if v := r.URL.Query().Get("page"); v != "" {
    87→		if p, err := strconv.Atoi(v); err == nil && p > 0 {
    88→			page = p
    89→		}
    90→	}
    91→	if v := r.URL.Query().Get("per_page"); v != "" {
    92→		if pp, err := strconv.Atoi(v); err == nil && pp > 0 && pp <= 100 {
    93→			perPage = pp
    94→		}
    95→	}
    96→	return
    97→}
    98→
    99→func DecodeJSON(r *http.Request, dst any) error {
   100→	return json.NewDecoder(r.Body).Decode(dst)
   101→}
   102→

