     6→  data: T;
     7→  meta?: ApiMeta;
     8→  error?: ApiError;
     9→}
    10→
    11→export interface ApiMeta {
    12→  page: number;
    13→  per_page: number;
    14→  total: number;
    15→}
    16→
    17→export interface ApiError {
    18→  code: string;
