    39→}
    40→
    41→export interface ProjectInput {
    42→  name: string;
    43→  description?: string;
    44→  agent_prompt?: string;
    45→  agent_rules?: AgentRules;
    46→}
    47→
    48→export interface Source {
    49→  id: string;
    50→  project_id: string;
    51→  provider: string;
    52→  repository: string;
    53→  poll_interval_seconds: number;
    54→  enabled: boolean;
