    24→
    25→
    26→const POLL_INTERVAL_OPTIONS = [
    27→    { label: "Hourly", value: "3600" },
    28→    { label: "Daily", value: "86400" },
    29→    { label: "Weekly", value: "604800" },
    30→    { label: "Monthly", value: "2592000" },
    31→  ];
    32→
    33→  function nearestPollInterval(seconds: number): string {
    34→    const values = POLL_INTERVAL_OPTIONS.map((o) => Number(o.value));
    35→    let closest = values[0];
    36→    for (const v of values) {
    37→      if (Math.abs(v - seconds) < Math.abs(closest - seconds)) closest = v;
    38→    }
    39→    return String(closest);
    40→  }
    41→
    42→
    43→export function SourceForm({ initial, onSubmit, title, redirectTo, onSuccess, onCancel }: SourceFormProps) {
    44→  const router = useRouter();
    45→  const [saving, setSaving] = useState(false);
    46→  const [error, setError] = useState("");
    47→  const [provider, setProvider] = useState(initial?.provider ?? "dockerhub");
    48→  const [repository, setRepository] = useState(initial?.repository ?? "");
    49→  const [pollInterval, setPollInterval] = useState(
    50→    nearestPollInterval(initial?.poll_interval_seconds ?? 86400)
    51→  );
    52→  const [enabled, setEnabled] = useState(initial?.enabled ?? true);
    53→  const [configJson, setConfigJson] = useState(
    54→    JSON.stringify(initial?.config ?? {}, null, 2)
    55→  );
    56→  const [versionFilterInclude, setVersionFilterInclude] = useState(initial?.version_filter_include ?? "");
    57→  const [versionFilterExclude, setVersionFilterExclude] = useState(initial?.version_filter_exclude ?? "");
    58→  const [excludePrereleases, setExcludePrereleases] = useState(initial?.exclude_prereleases ?? false);
    59→
    60→  const handleSubmit = async (e: React.FormEvent) => {
    61→    e.preventDefault();
    62→    setError("");
    63→
    64→    const repoError = validateRepository(provider, repository);
    65→    if (repoError) {
    66→      setError(repoError);
    67→      return;
    68→    }
    69→
    70→    let parsedConfig: Record<string, unknown> | undefined;
    71→    if (configJson.trim() && configJson.trim() !== "{}") {
    72→      try {
    73→        parsedConfig = JSON.parse(configJson);
    74→      } catch {
    75→        setError("Config must be valid JSON");
    76→        return;
    77→      }
    78→    }
    79→
    80→    setSaving(true);
    81→    try {
    82→      await onSubmit({
    83→        provider,
    84→        repository: repository.trim(),
    85→        poll_interval_seconds: Number(pollInterval),
    86→        enabled,
    87→        config: parsedConfig,
    88→        version_filter_include: versionFilterInclude.trim() || undefined,
    89→        version_filter_exclude: versionFilterExclude.trim() || undefined,
    90→        exclude_prereleases: excludePrereleases || undefined,
    91→      });
    92→      if (onSuccess) {
    93→        onSuccess();
    94→      } else {
    95→        router.push(redirectTo ?? "/sources");
    96→      }
    97→    } catch (err: unknown) {
    98→      setError(err instanceof Error ? err.message : "Failed to save");
    99→    } finally {
   100→      setSaving(false);
   101→    }
   102→  };
   103→
   104→  const handleCancel = () => {
   105→    if (onCancel) {
   106→      onCancel();
   107→    } else {
   108→      router.back();
   109→    }
   110→  };
   111→
   112→  const formContent = (
   113→    <form onSubmit={handleSubmit} className="space-y-4">
   114→      {error && <div className="rounded-md bg-red-50 p-3 text-sm text-red-700">{error}</div>}
   115→      <div className="space-y-2">
   116→        <Label>Provider</Label>
   117→        <Select value={provider} onValueChange={setProvider}>
   118→          <SelectTrigger><SelectValue /></SelectTrigger>
   119→          <SelectContent>
   120→            <SelectItem value="dockerhub">Docker Hub</SelectItem>
   121→            <SelectItem value="github">GitHub</SelectItem>
   122→            <SelectItem value="ecr-public">ECR Public</SelectItem>
   123→            <SelectItem value="gitlab">GitLab</SelectItem>
   124→          </SelectContent>
   125→        </Select>
   126→      </div>
   127→      <div className="space-y-2">
   128→        <Label htmlFor="repository">Repository</Label>
   129→        <Input id="repository" value={repository} onChange={(e) => setRepository(e.target.value)} placeholder="e.g. library/golang or ethereum/go-ethereum" required />
   130→      </div>
   131→      <div className="space-y-2">
   132→        <Label>Poll Interval</Label>
   133→        <Select value={pollInterval} onValueChange={setPollInterval}>
   134→          <SelectTrigger><SelectValue /></SelectTrigger>
   135→          <SelectContent>
   136→            {POLL_INTERVAL_OPTIONS.map((opt) => (
   137→              <SelectItem key={opt.value} value={opt.value}>{opt.label}</SelectItem>
   138→            ))}
   139→          </SelectContent>
   140→        </Select>
   141→      </div>
   142→      <div className="space-y-2">
   143→        <Label htmlFor="config">Config (JSON, optional)</Label>
   144→        <Textarea
   145→          id="config"
   146→          value={configJson}
   147→          onChange={(e) => setConfigJson(e.target.value)}
