"use client";

import { useState, Suspense } from "react";
import { useSearchParams } from "next/navigation";
import useSWR from "swr";
import Link from "next/link";
import {
  releases as releasesApi,
  projects as projectsApi,
} from "@/lib/api/client";
import { ProviderBadge } from "@/components/ui/provider-badge";
import { VersionChip } from "@/components/ui/version-chip";
import type { Release, Project } from "@/lib/api/types";
import { ExternalLink } from "lucide-react";

import { timeAgo } from "@/lib/format";

const PER_PAGE = 15;

function getProviderUrl(
  provider: string,
  repository: string,
  version: string
): string | null {
  switch (provider) {
    case "github":
      return `https://github.com/${repository}/releases/tag/${version}`;
    case "dockerhub":
      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    case "ecr-public":
      return `https://gallery.ecr.aws/${repository}`;
    case "gitlab":
      return `https://gitlab.com/${repository}/-/releases/${version}`;
    default:
      return null;
  }
}

/* ------------------------------------------------------------------ */
/*  Page                                                               */
/* ------------------------------------------------------------------ */

export default function ReleasesPage() {
  return (
    <Suspense>
      <ReleasesPageInner />
    </Suspense>
  );
}

function ReleasesPageInner() {
  const searchParams = useSearchParams();
  const initialProject = searchParams.get("project") ?? "all";
  const [page, setPage] = useState(1);
  const [projectFilter, setProjectFilter] = useState<string>(initialProject);

  /* Fetch projects for the filter dropdown */
  const { data: projectsData } = useSWR("projects-for-filter", async () => {
    const firstPage = await projectsApi.list(1, 100);
    return firstPage;
  });

  /* Fetch releases — scoped by project or all */
  const { data: scopedData, isLoading: scopedLoading } = useSWR(
    projectFilter !== "all" ? ["releases", page, projectFilter] : null,
    () => releasesApi.listByProject(projectFilter, page, PER_PAGE)
  );

  const { data: allReleasesData, isLoading: allLoading } = useSWR(
    projectFilter === "all" ? ["all-releases", page] : null,
    () => releasesApi.list(page, PER_PAGE)
  );

  const isLoading = projectFilter !== "all" ? scopedLoading : allLoading;

  /* Releases come pre-enriched with project/source metadata from the backend */
  const releases: Release[] =
    projectFilter !== "all"
      ? scopedData?.data ?? []
      : allReleasesData?.data ?? [];

  /* Pagination math */
  const activeData = projectFilter !== "all" ? scopedData : allReleasesData;
  const total = activeData?.meta?.total ?? 0;
  const totalPages = Math.max(1, Math.ceil(total / PER_PAGE));
  const startRow = (page - 1) * PER_PAGE + 1;
  const endRow = Math.min(page * PER_PAGE, total);

  return (
    <div className="space-y-6">
      {/* Page title */}
      <h1
        style={{
          fontFamily: "var(--font-fraunces)",
          fontSize: "24px",
          fontWeight: 700,
          color: "#111113",
        }}
      >
        Releases
      </h1>

      {/* Project filter */}
      <div>
        <select
          value={projectFilter}
          onChange={(e) => {
            setProjectFilter(e.target.value);
            setPage(1);
          }}
          className="appearance-none rounded-md bg-white px-3 py-2 pr-8 outline-none transition-shadow"
          style={{
            fontFamily: "var(--font-dm-sans)",
            fontSize: "13px",
            color: "#111113",
            border: "1px solid #e8e8e5",
          }}
          onFocus={(e) =>
            (e.currentTarget.style.boxShadow = "0 0 0 2px #e8601a40")
          }
          onBlur={(e) => (e.currentTarget.style.boxShadow = "none")}
        >
          <option value="all">All Projects</option>
          {projectsData?.data.map((p: Project) => (
            <option key={p.id} value={p.id}>
              {p.name}
            </option>
          ))}
        </select>
      </div>

      {/* Table card */}
      <div
        className="overflow-hidden rounded-lg bg-white"
        style={{ border: "1px solid #e8e8e5" }}
      >
        {isLoading ? (
          <div
            className="py-16 text-center"
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#6b7280",
            }}
          >
            Loading...
          </div>
        ) : releases.length === 0 ? (
          <div className="py-16 text-center">
            <p
              style={{
                fontFamily: "var(--font-fraunces)",
                fontStyle: "italic",
                fontSize: "15px",
                color: "#9ca3af",
              }}
            >
              No releases ingested yet
            </p>
          </div>
        ) : (
          <table className="w-full">
            <thead>
              <tr style={{ borderBottom: "1px solid #e8e8e5", backgroundColor: "#fafaf9" }}>
                {["Project", "Provider", "Repository", "Version", "Released", "Age", ""].map(
                  (col) => (
                    <th
                      key={col}
                      className="px-4 py-3 text-left"
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "11px",
                        fontWeight: 600,
                        textTransform: "uppercase" as const,
                        letterSpacing: "0.08em",
                        color: "#9ca3af",
                      }}
                    >
                      {col}
                    </th>
                  )
                )}
              </tr>
            </thead>
            <tbody>
              {releases.map((release) => (
                <tr
                  key={release.id}
                  className="transition-colors hover:bg-[#fafaf9]"
                  style={{ borderBottom: "1px solid #e8e8e5" }}
                >
                  {/* Project */}
                  <td className="px-4 py-3">
                    {release.project_id ? (
                      <Link
                        href={`/projects/${release.project_id}`}
                        className="hover:underline"
                        style={{
                          fontFamily: "var(--font-dm-sans)",
                          fontSize: "13px",
                          color: "#111113",
                          fontWeight: 500,
                        }}
                      >
                        {release.project_name ?? "\u2014"}
                      </Link>
                    ) : (
                      <span
                        style={{
                          fontFamily: "var(--font-dm-sans)",
                          fontSize: "13px",
                          color: "#9ca3af",
                        }}
                      >
                        {"\u2014"}
                      </span>
                    )}
                  </td>

                  {/* Provider */}
                  <td className="px-4 py-3">
                    {release.provider ? (
                      <ProviderBadge provider={release.provider} />
                    ) : (
                      <span
                        style={{
                          fontFamily: "var(--font-dm-sans)",
                          fontSize: "13px",
                          color: "#9ca3af",
                        }}
                      >
                        {"\u2014"}
                      </span>
                    )}
                  </td>

                  {/* Repository */}
                  <td className="px-4 py-3">
                    <span
                      style={{
                        fontFamily: "'JetBrains Mono', monospace",
                        fontSize: "12px",
                        color: "#374151",
                      }}
                    >
                      {release.repository ?? release.source_id}
                    </span>
                  </td>

                  {/* Version */}
                  <td className="px-4 py-3">
                    <Link href={`/releases/${release.id}`}>
                      <VersionChip version={release.version} />
                    </Link>
                  </td>

                  {/* Released date */}
                  <td className="px-4 py-3">
                    <span
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "13px",
                        color: "#6b7280",
                      }}
                    >
                      {release.released_at
                        ? new Date(release.released_at).toLocaleDateString()
                        : "\u2014"}
                    </span>
                  </td>

                  {/* Age */}
                  <td className="px-4 py-3">
                    <span
                      style={{
                        fontFamily: "var(--font-dm-sans)",
                        fontSize: "13px",
                        color: "#9ca3af",
                      }}
                    >
                      {timeAgo(release.released_at ?? release.created_at)}
                    </span>
                  </td>

                  {/* Provider link */}
                  <td className="px-4 py-3">
                    {release.provider && release.repository && (() => {
                      const url = getProviderUrl(release.provider, release.repository, release.version);
                      return url ? (
                        <a
                          href={url}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="inline-flex items-center transition-colors hover:opacity-70"
                          style={{ color: "#9ca3af" }}
                          title="View on provider"
                        >
                          <ExternalLink size={14} />
                        </a>
                      ) : null;
                    })()}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {/* Pagination */}
      {total > 0 && (
        <div className="flex items-center justify-between">
          <span
            style={{
              fontFamily: "var(--font-dm-sans)",
              fontSize: "13px",
              color: "#9ca3af",
            }}
          >
            {startRow}&ndash;{endRow} of {total}
          </span>
          <div className="flex items-center gap-2">
            <button
              disabled={page <= 1}
              onClick={() => setPage(page - 1)}
              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
              style={{
                fontFamily: "var(--font-dm-sans)",
                fontSize: "13px",
                color: "#374151",
                border: "1px solid #e8e8e5",
              }}
            >
              Previous
            </button>
            <button
              disabled={page >= totalPages}
              onClick={() => setPage(page + 1)}
              className="rounded-md bg-white px-3 py-1.5 transition-colors hover:bg-[#fafaf9] disabled:cursor-not-allowed disabled:opacity-40"
              style={{
                fontFamily: "var(--font-dm-sans)",
                fontSize: "13px",
                color: "#374151",
                border: "1px solid #e8e8e5",
              }}
            >
              Next
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

